/// when all values satisfying (X & Mask) == V are less than C.
/// For example: (icmp ult i8 %a, 5) & (icmp eq i8 (and i8 %a, -2), 2)
/// When (a & -2) == 2, a can only be 2 or 3, both less than 5, so simplify to (icmp eq (and a, -2), 2).
static Value *foldUltAndMaskedEq(ICmpInst *CmpULT, ICmpInst *CmpEq, bool IsAnd,
                                 InstCombiner::BuilderTy &Builder, const SimplifyQuery &Q) {
  if (!IsAnd)
    return nullptr;

  // Match (icmp ult X, C)
  Value *UltX;
  const APInt *UltC;
  if (CmpULT->getPredicate() != ICmpInst::ICMP_ULT ||
      !match(CmpULT, m_ICmp(ICmpInst::ICMP_ULT, m_Value(UltX), m_APInt(UltC))))
    return nullptr;

