  if (CmpEq->getPredicate() != ICmpInst::ICMP_EQ ||
      !match(CmpEq->getOperand(0), m_And(m_Value(Y), m_APInt(Mask))) ||
      !match(CmpEq->getOperand(1), m_APInt(V)))
    return nullptr;

  // Must be the same variable
  if (UltX != Y)
    return nullptr;

  // Check: (V & ~Mask) must equal V, otherwise the equation is unsatisfiable
  if ((*V & ~*Mask) != *V)
    return nullptr;

  // Compute the maximum value that satisfies (X & Mask) == V
  // Max value = V | ~Mask (all unconstrained bits set to 1)
  APInt MaxVal = *V | ~*Mask;

  // If MaxVal < UltC, then all values satisfying the masked equality are < UltC
  if (MaxVal.ult(*UltC)) {
    // Require that CmpULT has only one use so we can remove it
    if (!CmpULT->hasOneUse())
      return nullptr;
    return CmpEq;
  }

  return nullptr;
}

