/// Fold (icmp ult X, C) & (icmp eq (and X, Mask), V) into (icmp eq (and X, Mask), V)
/// when all values satisfying (X & Mask) == V are less than C.
/// For example: (icmp ult i8 %a, 5) & (icmp eq i8 (and i8 %a, -2), 2)
/// When (a & -2) == 2, a can only be 2 or 3, both less than 5, so simplify to (icmp eq (and a, -2), 2).
static Value *foldUltAndMaskedEq(ICmpInst *CmpULT, ICmpInst *CmpEq, bool IsAnd,
                                 InstCombiner::BuilderTy &Builder, const SimplifyQuery &Q) {
  if (!IsAnd)
    return nullptr;

  // Match (icmp ult X, C)
  Value *UltX;
  const APInt *UltC;
  if (CmpULT->getPredicate() != ICmpInst::ICMP_ULT ||
      !match(CmpULT, m_ICmp(ICmpInst::ICMP_ULT, m_Value(UltX), m_APInt(UltC))))
    return nullptr;

  // Match (icmp eq (and Y, Mask), V)
  Value *AndX, *Y;
  const APInt *Mask, *V;
  if (CmpEq->getPredicate() != ICmpInst::ICMP_EQ ||
      !match(CmpEq->getOperand(0), m_And(m_Value(Y), m_APInt(Mask))) ||
      !match(CmpEq->getOperand(1), m_APInt(V)))
    return nullptr;

  // Must be the same variable
  if (UltX != Y)
    return nullptr;

  // Check: (V & ~Mask) must equal V, otherwise the equation is unsatisfiable
  if ((*V & ~*Mask) != *V)
    return nullptr;

  // Compute the maximum value that satisfies (X & Mask) == V
  // Max value = V | ~Mask (all unconstrained bits set to 1)
  APInt MaxVal = *V | ~*Mask;

  // If MaxVal < UltC, then all values satisfying the masked equality are < UltC
  if (MaxVal.ult(*UltC)) {
    // Require that CmpULT has only one use so we can remove it
    if (!CmpULT->hasOneUse())
      return nullptr;
    return CmpEq;
  }

  return nullptr;
}

